class CheckpointDownloader:
    """Downloads and caches pretrained model checkpoints."""
    
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
    
    def download_checkpoint(self, model_name: str, force_download: bool = False) -> str:
        model_info = ModelRegistry.get_model_info(model_name)
        url = model_info["url"]
        filename = url.split("/")[-1]
        filepath = self.cache_dir / filename
        
        if filepath.exists() and not force_download:
            logger.info(f"Checkpoint already cached at {filepath}")
            return str(filepath)
        
        logger.info(f"Downloading {model_name} checkpoint from {url}...")
        try:
            urllib.request.urlretrieve(url, str(filepath), reporthook=self._download_progress)
            print()  # newline after progress
            logger.info(f"Download complete: {filepath}")
        except Exception as e:
            logger.error(f"Failed to download checkpoint: {e}")
            if filepath.exists():
                filepath.unlink()
            raise
        
        return str(filepath)
    
    def load_checkpoint(self, checkpoint_path: str, device: str = "cpu") -> Dict[str, Any]:
        logger.info(f"Loading checkpoint from {checkpoint_path}")
        checkpoint = torch.load(checkpoint_path, map_location=device, weights_only=False)
        return checkpoint
    
    def download_from_url(self, url: str, filename: Optional[str] = None) -> str:
        if filename is None:
            filename = url.split("/")[-1]
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            logger.info(f"File already cached at {filepath}")
            return str(filepath)
        
        logger.info(f"Downloading from {url}...")
        urllib.request.urlretrieve(url, str(filepath), reporthook=self._download_progress)
        print()
        logger.info(f"Download complete: {filepath}")
        return str(filepath)
    
    @staticmethod
    def _download_progress(block_num, block_size, total_size):
        downloaded = block_num * block_size
        if total_size > 0:
            percent = min(100, downloaded * 100 / total_size)
            print(f"\rProgress: {percent:.1f}% ({downloaded / 1e6:.1f}MB / {total_size / 1e6:.1f}MB)", end="")
        else:
            print(f"\rDownloaded: {downloaded / 1e6:.1f}MB", end="")


class ModelFactory:
    """Creates and configures models for transfer learning."""
    
    @staticmethod
    def create_model(architecture: str, pretrained_weights: Optional[Dict] = None,
                     num_classes: int = 1000) -> nn.Module:
        model_creators = {
            "resnet18": lambda: models.resnet18(weights=None),
            "resnet50": lambda: models.resnet50(weights=None),
            "vgg16": lambda: models.vgg16(weights=None),
            "mobilenet_v2": lambda: models.mobilenet_v2(weights=None),
            "efficientnet_b0": lambda: models.efficientnet_b0(weights=None),
        }
        
        if architecture not in model_creators:
            raise ValueError(f"Unsupported architecture: {architecture}")
        
        model = model_creators[architecture]()
        
        if pretrained_weights is not None:
            logger.info(f"Loading pretrained weights into {architecture}...")
            try:
                model.load_state_dict(pretrained_weights, strict=True)
                logger.info("Weights loaded successfully (strict mode)")
            except RuntimeError:
                logger.warning("Strict loading failed, trying non-strict mode...")
                missing, unexpected = model.load_state_dict(pretrained_weights, strict=False)
                if missing:
                    logger.warning(f"Missing keys: {len(missing)}")
                if unexpected:
                    logger.warning(f"Unexpected keys: {len(unexpected)}")
        
        return model
    
    @staticmethod
    def adapt_model_for_transfer(model: nn.Module, architecture: str,
                                  num_classes: int, freeze_backbone: bool = True) -> nn.Module:
        if freeze_backbone:
            for param in model.parameters():
                param.requires_grad = False
            logger.info("Backbone layers frozen")
        
        if architecture in ["resnet18", "resnet50"]:
            in_features = model.fc.in_features
            model.fc = nn.Sequential(
                nn.Dropout(0.3),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Dropout(0.2),
                nn.Linear(512, num_classes)
            )
            logger.info(f"Replaced fc layer: {in_features} -> 512 -> {num_classes}")
        
        elif architecture == "vgg16":
            in_features = model.classifier[6].in_features
            model.classifier[6] = nn.Sequential(
                nn.Dropout(0.3),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Linear(512, num_classes)
            )
            logger.info(f"Replaced VGG classifier: {in_features} -> 512 -> {num_classes}")
        
        elif architecture == "mobilenet_v2":
            in_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.3),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Linear(512, num_classes)
            )
            logger.info(f"Replaced MobileNetV2 classifier: {in_features} -> 512 -> {num_classes}")
        
        elif architecture == "efficientnet_b0":
            in_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.3),
                nn.Linear(in_features, 512),
                nn.ReLU(inplace=True),
                nn.Linear(512, num_classes)
            )
            logger.info(f"Replaced EfficientNet classifier: {in_features} -> 512 -> {num_classes}")
        
        trainable = sum(p.numel() for p in model.parameters() if p.requires_grad)
        total = sum(p.numel() for p in model.parameters())
        logger.info(f"Trainable parameters: {trainable:,} / {total:,} ({100 * trainable / total:.1f}%)")
        
        return model


class CustomImageDataset(Dataset):
    """A custom dataset that wraps image data for transfer learning."""
    
    def __init__(self, data, targets, transform=None):
        self.data = data
        self.targets = targets
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        image = self.data[idx]
        target = self.targets[idx]
        if self.transform:
            image = self.transform(image)
        return image, target


class DatasetManager:
    """Manages datasets for fine-tuning."""
    
    def __init__(self, data_dir: str = "./data"):
        self.data_dir = Path(data_dir)
        self.data_dir.mkdir(parents=True, exist_ok=True)
    
    def get_cifar10(self, batch_size: int = 32, num_workers: int = 2,
                     val_split: float = 0.1) -> Tuple[DataLoader, DataLoader, DataLoader]:
        train_transform = transforms.Compose([
            transforms.RandomHorizontalFlip(),
            transforms.RandomCrop(32, padding=4),
            transforms.Resize(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        test_transform = transforms.Compose([
            transforms.Resize(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        full_train = torchvision.datasets.CIFAR10(
            root=str(self.data_dir), train=True, download=True, transform=train_transform
        )
        test_dataset = torchvision.datasets.CIFAR10(
            root=str(self.data_dir), train=False, download=True, transform=test_transform
        )
        
        val_size = int(len(full_train) * val_split)
        train_size = len(full_train) - val_size
        train_dataset, val_dataset = random_split(full_train, [train_size, val_size])
        
        train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True,
                                   num_workers=num_workers, pin_memory=True)
        val_loader = DataLoader(val_dataset, batch_size=batch_size, shuffle=False,
                                 num_workers=num_workers, pin_memory=True)
        test_loader = DataLoader(test_dataset, batch_size=batch_size, shuffle=False,
                                  num_workers=num_workers, pin_memory=True)
        
        logger.info(f"CIFAR-10 loaded: train={train_size}, val={val_size}, test={len(test_dataset)}")
        return train_loader, val_loader, test_loader
    
